def factorial(n):
 if not isinstance(n, int) or n < 0:
  raise ValueError('n must be non-negative integer')
 result = 1
 for i in range(2, n+1):
  result *= i
 return result

def is_palindrome(s):
 s = ''.join(s.lower().split())
 return s == s[::-1]
